def validate_token(token: str) -> bool:
    return token == "ok"


check_token = validate_token


def login(token: str) -> str:
    if check_token(token):
        return "ok"
    return "denied"

class TokenFlow:
    def validate(self, token: str) -> bool:
        return token == "ok"

    def login(self, token: str) -> str:
        if self.validate(token):
            return "ok"
        return "denied"

